window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["map"]={"updatedAt":"2026-07-06","count":129,"nodes":[{"id":"nha-to-cua-huyen-gia","name":"Nhà Tổ của Huyễn gia","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Địa điểm trên Thiên Huyễn Tinh, nơi Huyễn gia Lão Tổ đang bế quan. Kiếm khí của Lăng Thiên Hầu truy kích qua lốc xoáy đã chấn động tới nơi này.","detail":"Nhà Tổ của Huyễn gia là nơi Huyễn gia Lão Tổ khoanh chân bế quan trong phòng có lốc xoáy trước mặt. Sau khi lão cứu Liễu Mi, kiếm khí của Lăng Thiên Hầu do Vương Lâm phóng ra truy kích đến đây, khiến lốc xoáy sụp đổ và lão phát ra tiếng kêu đau.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0635"]},{"id":"mat-that-cua-huyen-gia-lao-to","name":"Mật thất của Huyễn gia Lão Tổ","cn":"","capDo":"khac","parentId":"nha-to-cua-huyen-gia","blurb":"Căn mật thất trong Nhà Tổ Huyễn gia, nơi bạch quang cuốn Liễu Mi trở về sau khi thoát khỏi Vương Lâm. Bạch quang sau đó chui vào mi tâm Huyễn gia Lão Tổ.","detail":"Mật thất của Huyễn gia Lão Tổ nằm trong khu vực Nhà Tổ Huyễn gia trên Thiên Huyễn Tinh. Sau khi lốc xoáy cứu viện sụp đổ, bạch quang cuốn Liễu Mi vào căn phòng này, ném nàng sang một bên rồi nhập vào mi tâm Huyễn gia Lão Tổ.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0635"]},{"id":"tinh-khong","name":"Tinh không","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian rộng lớn giữa các tinh cầu, nơi Huyễn gia Lão Tổ dùng nguyên thần vượt qua để cứu Liễu Mi.","detail":"Trong chương này, Huyễn gia Lão Tổ dùng nguyên thần vượt tinh không để cứu Liễu Mi khỏi Vương Lâm. Kiếm khí của Lăng Thiên Hầu cũng truy theo thông đạo, khiến lão hoảng hốt tháo chạy về mật thất.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0636"]},{"id":"toa-tinh-dai-tran","name":"Tỏa Tinh đại trận","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Đại trận bao quanh hoặc liên quan Nhiễm Vân Tinh mà Vương Lâm xuyên qua khi rời tinh cầu.","detail":"Trước khi dùng Tinh La bàn lao vào tinh không, Vương Lâm đạp hư không và xuyên qua Tỏa Tinh đại trận, rời Nhiễm Vân Tinh để đi tới Thiên Huyễn Tinh.","theLucLienQuan":[],"nguon":["@c0637"]},{"id":"thanh-tri-xa-xa-nhiem-van-tinh","name":"Thành trì xa xa","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh","blurb":"Thành trì trên Nhiễm Vân Tinh nơi Tôn Tích ẩn mình quan sát trước khi ra gặp Vương Lâm.","detail":"Tôn Tích từ trong thành trì xa xa bay ra sau khi chứng kiến trận chiến trước đó, mang tâm trạng sợ hãi khi đối diện Vương Lâm và thú nhận chuyện cũ.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0637"]},{"id":"phia-nam-thien-huyen-tinh","name":"Phía Nam Thiên Huyễn Tinh","cn":"","capDo":"vuc","parentId":"thien-huyen-tinh","blurb":"Khu vực Huyễn gia tập trung trực hệ tộc nhân và mở hộ tộc đại trận. Vương Lâm khóa thần thức về hướng này rồi lao tới Nhà Tổ Huyễn gia.","detail":"Phía Nam Thiên Huyễn Tinh là địa bàn Huyễn gia co cụm khi biết Vương Lâm sắp tới. Hộ tộc đại trận được mở bao phủ khu vực này, còn các tu sĩ bậc cao được phái đi đón tộc nhân chưa kịp trở về.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0638"]},{"id":"phuong-bac-va-phuong-dong-thien-huyen-tinh","name":"Phương Bắc và phương Đông Thiên Huyễn Tinh","cn":"","capDo":"vuc","parentId":"thien-huyen-tinh","blurb":"Địa bàn do Thiên gia chiếm cứ trên Thiên Huyễn Tinh. Vị thế này đến từ thực lực ba lão tổ bước thứ hai của Thiên gia.","detail":"Trong thế cục ba đại gia tộc, Thiên gia mạnh nhất và chiếm phương Bắc cùng phương Đông Thiên Huyễn Tinh. Chương dùng địa bàn này để làm rõ tương quan Thiên gia vượt trên Huyễn gia và Hứa gia.","theLucLienQuan":["Thiên gia"],"nguon":["@c0638"]},{"id":"la-thien-tinh-vuc","name":"La Thiên Tinh Vực","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực bao gồm Thiên Huyễn Tinh và Đông Lâm Tinh. Đây cũng là không gian thế lực nơi Lôi Tiên Điện có uy danh khiến Thiên Quỳ Tử e sợ.","detail":"La Thiên Tinh Vực được nhắc qua vị trí của Đông Lâm Tinh, Thiên Huyễn Tinh và uy thế Lôi Tiên Điện. Việc Thiên Quỳ Tử nhìn thấy Lôi Thú rồi sợ hãi cho thấy Lôi Tiên Điện có ảnh hưởng rất lớn trong khu vực này.","theLucLienQuan":["Lôi Tiên Điện","Thiên gia","Huyễn gia","Hứa gia"],"nguon":["@c0638"]},{"id":"loi-tien-gioi","name":"Lôi Tiên giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Nơi gắn với Lôi Tiên Điện, Lôi Tiên Quân và nguồn gốc Lôi Thú của Xạ Thần xa. Chương này dùng Lôi Tiên giới để giải thích vì sao Xạ Thần xa có thể hóa Lôi Thú.","detail":"Người luyện chế Xạ Thần xa từng tới Lôi Tiên giới và lấy vài đầu Lôi Thú từ Lôi Tiên Quân để luyện Thú hồn. Vì vậy Vương Lâm sở hữu Lôi Thú khiến Thiên Quỳ Tử lầm tưởng hắn là người Lôi Tiên Điện, dù Huyễn Vô Tình phủ nhận điều đó.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0638","@c0678","@c0701"],"aliases":["Lôi Chi Tiên Giới","Lôi tiên giới"]},{"id":"vuc-sau-trieu-tich","name":"Vực sâu triều tịch","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm được nhắc trong hồi cố về kiếm khí Lăng Thiên Hậu. Vương Lâm từng lấy thêm kiếm khí dưới Vực sâu triều tịch.","detail":"Chương nhắc lại quá trình Vương Lâm có kiếm khí của Lăng Thiên Hậu: từng có hai đạo, dùng một đạo giúp Cổ Yêu, sau đó lấy thêm hai đạo dưới Vực sâu triều tịch. Nơi này không trực tiếp xuất hiện trong hiện tại chương.","theLucLienQuan":[],"nguon":["@c0638"]},{"id":"huyen-gia-dai-tran","name":"Huyễn gia đại trận","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Huyễn gia đại trận là không gian phòng hộ bao quanh Huyễn gia trên Thiên Huyễn Tinh.","detail":"Trong chương này, các tộc nhân Huyễn gia đứng bên trong đại trận và trực tiếp chịu áp lực từ lôi uy của Lôi Thú, công kích của Tiên vệ và kiếm thức của Vương Lâm. Trận pháp bị ép đến xu hướng suy tàn nhưng trước Trảm La Quyết vẫn chưa hoàn toàn bị phá.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0639"]},{"id":"thien-gia-dia-diem","name":"Thiên gia","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Thiên gia là địa điểm trên Thiên Huyễn Tinh nơi Thiên Quỳ Tử quan sát biến cố Huyễn gia.","detail":"Khi Huyễn gia đại trận bị Vương Lâm công kích, Thiên Quỳ Tử ở Thiên gia quan sát diễn biến và cười lạnh trước tình thế Huyễn gia gặp nguy.","theLucLienQuan":["Thiên gia"],"nguon":["@c0639"]},{"id":"tu-duong-cua-huyen-gia","name":"Từ đường của Huyễn gia","cn":"","capDo":"khac","parentId":"nha-to-cua-huyen-gia","blurb":"Nơi Phúc Trạch ngọc giản màu vàng ngọc chậm rãi bay lên khi Huyễn Vô Tình mời chí bảo Huyễn gia ra trận.","detail":"Từ đường của Huyễn gia nằm trong phạm vi Nhà Tổ Huyễn gia. Trong chương này, Phúc Trạch ngọc giản từ nơi đây bay lên, tỏa lực lượng tường hòa và mở đầu cho việc chí bảo Huyễn gia hóa hình tấn công Vương Lâm.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0640"]},{"id":"mat-that-o-thien-gia","name":"Mật thất ở Thiên gia","cn":"","capDo":"khac","parentId":"thien-gia-dia-diem","blurb":"Nơi Thiên Quỳ Tử ngồi quan sát trận chiến Huyễn gia bằng thần thức. Ông đứng bật dậy khi nhận ra quy tắc trong kiếm thức của Vương Lâm.","detail":"Trong mật thất ở Thiên gia, Thiên Quỳ Tử dùng thần thức theo dõi biến cố tại Nhà Tổ Huyễn gia. Từ đây ông nhận ra một kiếm của Vương Lâm ẩn chứa quy tắc và suy đoán về quan hệ giữa Vương Lâm với Lôi Tiên Điện.","theLucLienQuan":["Thiên gia"],"nguon":["@c0640"]},{"id":"hua-gia-dia-diem","name":"Hứa gia","cn":"","capDo":"khac","parentId":"thien-huyen-tinh","blurb":"Địa điểm của Hứa gia trên Thiên Huyễn Tinh, nơi lão già Hứa gia theo dõi trận chiến Huyễn gia. Ông từng định ra tay tương trợ nhưng dừng lại vì kiêng dè hậu thủ của Vương Lâm.","detail":"Từ Hứa gia, lão giả dùng thần thức quan sát Nhà Tổ Huyễn gia. Khi một kiếm của Vương Lâm phá đại trận, ông cân nhắc ước định với Huyễn gia Lão Tổ nhưng quyết định không lập tức can thiệp.","theLucLienQuan":["Hứa gia"],"nguon":["@c0640"]},{"id":"tien-nghich-khong-gian-dia-diem","name":"Tiên Nghịch không gian","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian nơi có Oán Anh mà Vương Lâm nhớ tới trong lúc đối diện Phúc Trạch ngọc giản. Đây là địa điểm đặc thù gắn với con bài của Vương Lâm.","detail":"Khi bóng người do Phúc Trạch ngọc giản hóa thành áp tới, Vương Lâm nhớ tới Oán Anh trong Tiên Nghịch không gian. Chi tiết này dẫn vào việc hắn gọi một tồn tại trong nguyên thần và hứa thả tự do sau trận.","theLucLienQuan":["Vương Lâm"],"nguon":["@c0640"]},{"id":"yeu-linh-chi-dia","name":"Yêu Linh chi địa","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Địa điểm Vương Lâm từng chứng kiến Tham Lang dùng Tiên sơn pháp bảo rút Sơn hồn.","detail":"Trong chương này, Yêu Linh chi địa được nhắc lại như mốc so sánh: cảnh Tham Lang rút Sơn hồn bằng Tiên sơn pháp bảo kém xa quy mô Tán Ma rút tinh hồn Thiên Huyễn Tinh.","theLucLienQuan":["Tham Lang"],"nguon":["@c0642"]},{"id":"lac-nguyet-thon","name":"Lạc Nguyệt thôn","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Lạc Nguyệt thôn là sơn thôn trên Nhiễm Vân Tinh nơi Vương Lâm sống ẩn sau biến cố Huyễn gia. Tại đây hắn ở trong một căn nhà nhỏ cùng Vương Bình.","detail":"Nhiều ngày sau khi rời Huyễn gia, Vương Lâm xuất hiện tại Lạc Nguyệt thôn trong thân phận thợ mộc. Sơn thôn có đời sống phàm tục bình dị, đám trẻ tụ tập nghe chuyện Kỳ Liên Phong, còn dân thôn qua lại nhờ Vương Lâm làm đồ đạc.","theLucLienQuan":["Lạc Nguyệt thôn"],"nguon":["@c0643"]},{"id":"ky-lien-phong","name":"Kỳ Liên Phong","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Kỳ Liên Phong là ngọn núi gần Lạc Nguyệt thôn. Thiếu niên họ Chu kể nơi này từng có sương mù giúp cường thân kiện thể, nhưng đã không còn từ năm năm trước.","detail":"Trong đời sống của nhóm trẻ Lạc Nguyệt thôn, Kỳ Liên Phong là địa điểm gắn với lời kể về sương mù và luyện kiếm. Vương Bình nghe chuyện này rồi muốn nhờ cha đưa đi xem.","theLucLienQuan":["Lạc Nguyệt thôn"],"nguon":["@c0643"]},{"id":"chu-tuoc-mo","name":"Chu Tước Mộ","cn":"","capDo":"khac","parentId":"chu-tuoc-tinh","blurb":"Chu Tước Mộ là địa điểm gắn với những việc khiến Liễu Mi oán hận Vương Lâm. Chương này nhắc lại nơi ấy trong dòng hồi tưởng trước khi nàng tiêu tán.","detail":"Khi Liễu Mi nhớ lại nhân quả với Vương Lâm, Chu Tước Mộ được nhắc như một phần nguồn cơn oán hận của nàng đối với hắn.","theLucLienQuan":["Chu Tước Tinh"],"nguon":["@c0643"]},{"id":"hau-son-thon-lac-nguyet","name":"Hậu sơn thôn Lạc Nguyệt","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Khu sau núi cạnh thôn Lạc Nguyệt, nơi an táng Tôn Thái sau khi lão qua đời.","detail":"Sau khi Tôn Thái đại nạn qua đời, mộ của lão được đặt ở sau núi cạnh thôn Lạc Nguyệt. Mộ bia do Vương Bình khắc, ghi tên Tôn Thái và thân phận nghĩa tôn của mình.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"truong-tu-thuc-trong-thon","name":"Trường tư thục trong thôn","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Trường học trong thôn Lạc Nguyệt, được dựng vào mùa xuân để trẻ nhỏ trong thôn học chữ.","detail":"Trong giai đoạn đời sống phàm tục của phụ tử Vương Lâm, thôn Lạc Nguyệt có trường tư thục được dựng lên vào mùa xuân, giúp trẻ nhỏ trong thôn có nơi học chữ.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"vu-chi-tien-gioi","name":"Vũ Chi Tiên Giới","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian được Tôn Thái hồi tưởng trong khoảnh khắc trước khi qua đời.","detail":"Trước lúc mất, Tôn Thái nhớ lại những chuyện mấy trăm năm trước ở Vũ Chi Tiên Giới. Địa danh này gắn với gút mắc cũ giữa lão và Vương Lâm, cũng là nguồn của lời hứa mà Vương Lâm nhắc lại khi lão lâm chung.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"lien-minh-tu-chan-dia-vuc","name":"Liên Minh Tu Chân","cn":"","capDo":"vuc","parentId":null,"blurb":"Khu vực tu chân nơi Huyễn Gia Lão Tổ từng tìm kiếm hạt châu Thiên Nghịch.","detail":"Liên Minh Tu Chân được nhắc trong mạch giải thích về Huyễn Gia Lão Tổ: lão từng tìm kiếm hạt châu Thiên Nghịch tại đây, rồi tạm bỏ việc ấy để đưa Liễu Mi về Huyễn gia khi phát hiện dấu hiệu thăng hoa ý cảnh của nàng.","theLucLienQuan":["Liên Minh Tu Chân","Huyễn gia"],"nguon":["@c0645"]},{"id":"dai-vien-vuong-gia","name":"Đại viện Vương gia","cn":"","capDo":"khac","parentId":"lac-nguyet-thon","blurb":"Không gian sinh hoạt của Vương Lâm và Vương Bình tại Lạc Nguyệt thôn. Đây là nơi Vương Lâm dạy con điêu khắc và đối thoại với con về việc tu đạo.","detail":"Đại viện Vương gia là nơi hai cha con Vương Lâm sống trong những năm cuối ở Lạc Nguyệt thôn. Trong sân, Vương Bình tập khắc tượng gỗ, còn Vương Lâm giảng cho con rằng điêu khắc phải dùng tâm và ký ức; cũng tại đây, Vương Lâm dứt khoát cấm Vương Bình tu đạo.","theLucLienQuan":["Vương gia"],"nguon":["@c0646"]},{"id":"nhiem-van-tinh","name":"Nhiễm Vân tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi phụ tử Vương Lâm thực hiện hành trình tám năm qua núi, sông và biển. Linh khí nơi đây đã suy giảm sau hạo kiếp nhưng vẫn được so với Chu Tước tinh năm xưa.","detail":"Nhiễm Vân tinh là không gian chính của chương, nơi Vương Lâm dẫn Vương Bình leo qua nhiều danh sơn, vượt hơn phân nửa sông ngòi rồi ra biển rộng để rèn tâm linh. Trải nghiệm thiên địa trên tinh cầu này giúp Vương Bình hoàn thành một lần thăng hoa lớn dù vẫn là phàm nhân.","theLucLienQuan":[],"nguon":["@c0647"]},{"id":"chu-tuoc-tinh","name":"Chu Tước tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu được dùng để so sánh với Nhiễm Vân tinh về mức độ linh khí. Chi tiết này nhấn mạnh Nhiễm Vân tinh dù suy giảm vẫn còn hơn Chu Tước tinh năm xưa.","detail":"Chu Tước tinh được nhắc trong phần mô tả Nhiễm Vân tinh, làm mốc so sánh về linh khí. Sự đối chiếu cho thấy bối cảnh tu luyện của Nhiễm Vân tinh sau hạo kiếp vẫn chưa hoàn toàn cằn cỗi như Chu Tước tinh trong quá khứ.","theLucLienQuan":[],"nguon":["@c0647"]},{"id":"ky-thuy-thanh","name":"Kỳ Thủy thành","cn":"","aliases":["Kỳ Thủy Thành"],"capDo":"thanh","parentId":"dai-tan-quoc-dia-diem","blurb":"Phó đô phồn hoa của Đại Tần quốc trên Nhiễm Vân tinh. Vương Lâm đưa Vương Bình vào thành và quyết định hai cha con sẽ sống tại đây.","detail":"Kỳ Thủy thành là một trong các phó đô của Đại Tần quốc, được miêu tả phồn hoa, náo nhiệt, gần sông ngòi và mức độ sầm uất gần với kinh đô. Sau khi xe ngựa tới nơi, Vương Lâm nói với Vương Bình rằng từ nay hai cha con sẽ sống ở đây và sẽ đi mua một tòa nhà.","theLucLienQuan":["Đại Tần quốc"],"nguon":["@c0648"]},{"id":"dai-tan-quoc-dia-diem","name":"Đại Tần quốc","cn":"","aliases":["Đại Tần"],"capDo":"quoc-gia","parentId":"nhiem-van-tinh","blurb":"Quốc gia trên Nhiễm Vân tinh, có Kỳ Thủy thành là một phó đô. Đại Tần quốc thuộc nhóm ba đại đế quốc của tinh cầu này.","detail":"Đại Tần quốc là quốc gia nơi Kỳ Thủy thành tọa lạc. Chương giới thiệu Kỳ Thủy thành là một trong các phó đô của Đại Tần quốc và đặt Đại Tần quốc trong nhóm ba đại đế quốc trên Nhiễm Vân tinh.","theLucLienQuan":["Đại Tần quốc"],"nguon":["@c0648"]},{"id":"tinh-nha-hien","name":"Tĩnh Nhã Hiên","cn":"","aliases":[],"capDo":"khac","parentId":"ky-thuy-thanh","blurb":"Tửu quán hoa lệ ở thành đông Kỳ Thủy thành. Đây là nơi phụ tử Vương Lâm gặp nhóm lão nhân cẩm y, thanh niên tử y và Thanh nhi sư muội.","detail":"Tĩnh Nhã Hiên nằm ở thành đông Kỳ Thủy thành, được miêu tả là tửu quán hoa lệ. Sau khi vào thành, Vương Lâm và Vương Bình tới đây dùng bữa; xung đột nổ ra khi thanh niên tử y nhục mạ Vương Bình, lão nhân cẩm y ra tay, rồi bị Vương Lâm dùng ánh mắt trọng thương.","theLucLienQuan":["Đại Tần quốc"],"nguon":["@c0648"]},{"id":"thanh-bac-ky-thuy-thanh","name":"Thành bắc Kỳ Thủy Thành","cn":"","capDo":"khac","parentId":"ky-thuy-thanh","blurb":"Khu vực phía bắc Kỳ Thủy Thành, nơi có Vương phủ của phụ tử Vương Lâm. Đoàn Tôn gia dừng lại ngoài phủ khoảng trăm trượng trước khi bái kiến.","detail":"Thành bắc Kỳ Thủy Thành là vị trí đặt Vương phủ, nơi Tôn gia tới tìm phụ tử Vương Lâm sau sự việc ở tửu lâu. Tại đây, lão nhân mặt đỏ vừa xông vào phủ đã bị lực lượng vô hình chấn thương, khiến Tôn Khải Tinh vội rút lui.","theLucLienQuan":["Tôn gia"],"nguon":["@c0651"]},{"id":"dai-dien-chi-nhanh-ton-gia-o-ky-thuy-thanh","name":"Đại điện chi nhánh Tôn gia ở Kỳ Thủy Thành","cn":"","capDo":"khac","parentId":"ky-thuy-thanh","blurb":"Nơi Tôn Khải Tinh đưa toàn bộ tộc nhân trở về sau khi rời Vương phủ. Tại đây ông ra lệnh cấm người Tôn gia tới gần nơi ở của vị tiền bối.","detail":"Sau khi nhận ra khí tức Vấn Đỉnh trong Vương phủ, Tôn Khải Tinh lập tức đưa người Tôn gia trở về đại điện chi nhánh tại Kỳ Thủy Thành. Ông tuyên bố người nào bước vào phạm vi một ngàn trượng quanh nơi ở của tiền bối sẽ bị phế tu vi và trục xuất khỏi gia môn.","theLucLienQuan":["Tôn gia"],"nguon":["@c0651"]},{"id":"van-hai-tinh","name":"Vân Hải tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Một trong năm chủ tinh của La Thiên Bắc Vực, địa bàn của Vân gia. Vân Vô Phong xuất thân từ gia tộc này trên Vân Hải tinh.","detail":"Vân Hải tinh là nơi đặt Vân gia, đại gia tộc được gọi là đệ nhất gia tộc ở tinh cầu này. Thân phận đến từ Vân Hải tinh giúp Vân Vô Phong được các gia tộc tu chân trên Nhiễm Vân tinh nể mặt dù hắn không thể tu đạo.","theLucLienQuan":["Vân gia"],"nguon":["@c0651"]},{"id":"la-thien-bac-vuc","name":"La Thiên Bắc Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực lớn bao gồm Vân Hải tinh và Nhiễm Vân tinh. Danh tiếng Hứa Mộc từng lan rộng tại đây sau trận quét sạch Huyễn gia.","detail":"La Thiên Bắc Vực được nhắc như khu vực có năm chủ tinh, trong đó có Vân Hải tinh. Trận Hứa Mộc quét sạch Huyễn gia trên Nhiễm Vân tinh từng khiến danh tiếng của ông lưu truyền rộng trong vùng này.","theLucLienQuan":["Vân gia","Huyễn gia"],"nguon":["@c0651","@c0665"]},{"id":"bac-bo-nhiem-van-tinh","name":"Bắc bộ Nhiễm Vân tinh","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Khu vực phía bắc Nhiễm Vân tinh, nơi Thiên Hành phái xuất hiện sau ba năm Vương Bình rời Kỳ Thủy Thành. Giáo phái này nhanh chóng phát triển trong thế giới phàm nhân.","detail":"Bắc bộ Nhiễm Vân tinh trở thành nơi lưu truyền Thiên Hành phái trong phàm nhân. Tin đồn về thủ lĩnh giống tiên nhân và một nữ nhân luôn đi bên cạnh bắt đầu từ khu vực này rồi lan rộng.","theLucLienQuan":["Thiên Hành phái"],"nguon":["@c0651"]},{"id":"do-thanh-de-son-quoc","name":"Đô thành Đế Sơn quốc","cn":"","capDo":"thanh","parentId":"de-son-quoc","blurb":"Đô thành Đế Sơn quốc nằm ở bắc bộ Nhiễm Vân Tinh. Đây là nơi Vương Bình ngồi trong điện phủ xa hoa nhìn bản đồ và nhớ tới phụ thân.","detail":"Trong giai đoạn Thiên Hành phái lớn mạnh, đô thành Đế Sơn quốc là trung tâm thế tục nơi Vương Bình xử lý cục diện trước khi Đế Sơn quốc bị thay thế. Cảnh đêm tại điện phủ cho thấy Vương Bình đã rời xa sơn thôn tuổi trẻ và đứng giữa vòng xoáy quyền lực.","theLucLienQuan":["Đế Sơn quốc","Thiên Hành phái","Thiên Hành đế quốc"],"nguon":["@c0652"]},{"id":"ky-lien-son","name":"Kỳ Liên Sơn","cn":"","capDo":"vuc","parentId":"nhiem-van-tinh","blurb":"Kỳ Liên Sơn là dãy núi Vương Bình nhìn về từ doanh trướng khi đã trở thành chí tôn phàm nhân. Nơi này gợi lại sơn thôn và thời thơ ấu của hắn.","detail":"Khi chiến sự đang diễn ra, Vương Bình ra ngoài doanh trướng nhìn về hướng Kỳ Liên Sơn. Thanh Nghi nhắc đó là nơi gắn với thời thơ ấu của hắn, làm nổi bật nỗi mệt mỏi của Vương Bình trước quyền lực thế tục.","theLucLienQuan":["Thiên Hành đế quốc"],"nguon":["@c0652"]},{"id":"thon-nho-trong-nui","name":"Thôn nhỏ trong núi","cn":"","aliases":[],"capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Thôn nhỏ trên Nhiễm Vân tinh nơi Vương Bình và Thanh Nghi cư trú trong biến cố Lôi Đạo Tử.","detail":"Đây là nơi thần thức Lôi Đạo Tử tập trung sau khi hắn bao trùm toàn bộ Nhiễm Vân tinh. Vương Bình và Thanh Nghi đối diện Lôi Đạo Tử tại căn phòng trong thôn, trước khi lôi quang của hắn phá tan căn phòng và đẩy hai người vào nguy hiểm trực tiếp.","theLucLienQuan":[],"nguon":["@c0655"]},{"id":"thon-tren-nhiem-van-tinh","name":"Thôn trên Nhiễm Vân tinh","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Ngôi thôn nơi Lôi Đạo Tử tấn công Vương Bình trước khi Vương Lâm hiện thân cứu con.","detail":"Tại thôn này, Vương Bình đối diện lôi quang của Lôi Đạo Tử và được Vương Lâm dùng Định cứu kịp thời. Thôn dân không xuất hiện trong cuộc đối đầu vì trước đó đã bị thần thức quét qua làm bất tỉnh.","theLucLienQuan":[],"nguon":["@c0656"]},{"id":"binh-nguyen-phia-tay-nhiem-van-tinh","name":"Bình nguyên phía tây Nhiễm Vân tinh","cn":"","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Chiến trường Vương Lâm chọn sau khi đưa Vương Bình và Thanh Nghi rời khỏi thôn.","detail":"Vương Lâm dùng ánh sáng dịu dàng bao lấy Vương Bình và Thanh Nghi rồi đưa họ tới bình nguyên phía tây Nhiễm Vân tinh để tránh liên lụy thôn dân. Lôi Đạo Tử đuổi tới, xuất hiện cách đó năm trăm trượng và giao chiến với Vương Lâm tại đây.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0656"]},{"id":"tinh-cau-mau-xam-hoang-phe","name":"Tinh cầu màu xám hoang phế","cn":"","capDo":"tinh-cau","parentId":"tinh-khong","blurb":"Tinh cầu hoang không có linh lực, nơi Vương Lâm đưa Lôi Đạo Tử tới để tiếp tục xử lý.","detail":"Tinh cầu này có đất xám, gió bão và khí độc, không có linh lực. Vương Lâm chọn nơi đây để mở động phủ tạm, hạ cấm chế và bắt đầu luyện Lôi Đạo Tử thành tiên vệ.","theLucLienQuan":[],"nguon":["@c0660"]},{"id":"dong-phu-moi-tren-tinh-cau-mau-xam","name":"Động phủ mới trên tinh cầu màu xám","cn":"","capDo":"khac","parentId":"tinh-cau-mau-xam-hoang-phe","blurb":"Động phủ tạm do Vương Lâm dùng kiếm khí khoét ra trên tinh cầu xám.","detail":"Động phủ gồm bốn phòng một đại sảnh, được Vương Lâm dùng kiếm khí đẽo gọt mà thành. Đây là nơi hắn khiến Lôi Đạo Tử tưởng chỉ chịu cấm chế thứ hai, rồi thật sự bắt đầu luyện chế đối phương thành tiên vệ.","theLucLienQuan":[],"nguon":["@c0660"]},{"id":"dong-phu-tren-tinh-cau-bo-hoang","name":"Động phủ","cn":"","capDo":"khac","parentId":"tinh-cau-mau-xam-hoang-phe","blurb":"Động phủ trên tinh cầu bỏ hoang, nơi Vương Lâm khống chế nguyên thần và tế luyện thân thể Lôi Đạo Tử.","detail":"Trong động phủ này, Vương Lâm bố trí tiên vệ khôi lỗi, lôi thú, ba chung cực chủ hồn, Thất Tinh kiếm trận và cấm chế điện quang để áp chế nguyên thần Lôi Đạo Tử, đồng thời tiến hành tế luyện thân thể hắn thành tiên vệ khôi lỗi.","theLucLienQuan":[],"nguon":["@c0661"]},{"id":"tieu-tinh-cau-hoang-da-thuoc-pham-vi-huyet-to","name":"Tiểu tinh cầu hoang dã thuộc phạm vi Huyết Tổ","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tiểu tinh cầu hoang dã thuộc phạm vi Huyết Tổ, không có sinh linh và đang chết dần. Đây là nơi Tử Tâm điều tra trước khi tinh cầu tan vỡ để lộ bản tôn Vương Lâm.","detail":"Tinh cầu này có mặt đất khô nứt, núi sụp, sông cạn và biến đổi kỳ dị trong nhiều năm, giống như đã sống ngắn ngủi rồi đi tới tận cùng. Khi Tử Tâm dùng thần thức dò vào sâu, nàng bị uy áp bên trong đẩy lui; sau đó tinh cầu sụp đổ, sóng gợn bùng phát và bản tôn Vương Lâm hiện ra từ trung tâm.","theLucLienQuan":["Huyết Tổ thế lực"],"nguon":["@c0663"]},{"id":"tinh-cau-hoang-da-co-tang-loi-quang","name":"Tinh cầu hoang dã có tầng lôi quang","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tinh cầu hoang dã có tầng lôi quang tự nhiên bao phủ. Bản tôn Vương Lâm chọn nơi này để dung nhập vào lòng tinh cầu và tiếp tục tu luyện.","detail":"Vài tháng sau khi rời tinh cầu đã tan vỡ, bản tôn Vương Lâm chọn một tinh cầu hoang dã có tầng lôi quang tự nhiên. Hắn nhìn trúng đặc điểm này, dung nhập vào lòng tinh cầu rồi khoanh chân nhắm mắt tiếp tục tu luyện.","theLucLienQuan":[],"nguon":["@c0663"]},{"id":"huyet-hai-co-than-chi-dia","name":"Huyết Hải","cn":"","capDo":"khac","parentId":"co-than-chi-dia","blurb":"Huyết Hải nằm bên trong Cổ Thần Chi Địa. Đây là nơi nhiều tu sĩ khoanh chân hấp thu lực lượng, còn Thác Sâm ngồi trên cột đá lớn nhất.","detail":"Trong Huyết Hải của Cổ Thần Chi Địa, nhiều tu sĩ khoanh chân tu luyện và tu vi tăng mạnh. Ở cột đá lớn nhất, Thác Sâm khắc đầy tên Vương Lâm, bên cạnh có thiết kiếm rỉ sét và tuyên bố sắp thoát khỏi nơi này.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0663"]},{"id":"dinh-chu-tuoc-son","name":"Đỉnh Chu Tước Sơn","cn":"","capDo":"khac","parentId":"chu-tuoc-son","blurb":"Đỉnh Chu Tước Sơn là nơi Chu Như mở túi trữ vật Vương Lâm lưu lại. Tại đây, ký ức bị phong ấn của nàng được bạch quang giải khai.","detail":"Trên đỉnh Chu Tước Sơn, Chu Như đã trưởng thành hơn và cầm túi trữ vật cũ của Vương Lâm. Khi nàng mở túi, bạch quang nhập vào mi tâm, ký ức bị phong ấn chậm rãi cởi bỏ, khiến nàng khóc bên Tiểu Bạch.","theLucLienQuan":["Chu Tước Tinh"],"nguon":["@c0663"]},{"id":"vong-nguyet","name":"Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Ký sinh thể của Cổ Thần trên Vân Hà tinh được Vương Lâm nghĩ tới khi tìm Cổ Thần Khí.","detail":"Vương Lâm cho rằng Vọng Nguyệt thân là ký sinh thể của Cổ Thần, có thể còn liên quan tới Cổ Thần Khí còn sót lại. Vì bản tôn cần Cổ Thần Khí để trưởng thành, hắn dự định sau này nên tới Vân Hà tinh thăm dò.","theLucLienQuan":["Cổ Tộc"],"nguon":["@c0664"]},{"id":"loi-chi-tien-gioi","name":"Lôi Chi tiên giới","cn":"","capDo":"gioi-nho","parentId":"la-thien-tinh-vuc","blurb":"Nơi sẽ mở ra sau trăm năm và gắn với cơ hội của Huyễn Gia.","detail":"Huyễn Phong Thần nói Huyễn Gia giao toàn bộ Thăng Tiên quả cho Vương Lâm đồng nghĩa buông bỏ cơ hội tiến vào Lôi Chi tiên giới sau trăm năm.","theLucLienQuan":["Huyễn Gia","Lôi Tiên Điện"],"nguon":["@c0664"]},{"id":"thien-gia-thanh","name":"Thiên gia thành","cn":"","capDo":"thanh","parentId":"thien-huyen-tinh","blurb":"Thành trì của Thiên gia trên Thiên Huyễn Tinh.","detail":"Nơi Thiên Quỳ Tử cùng một ngàn tu sĩ Thiên gia ra ngoài cung kính nghênh đón Vương Lâm trong thân phận Sứ giả Lôi Tiên Điện.","theLucLienQuan":["Thiên gia"],"nguon":["@c0665"]},{"id":"van-ha-tinh","name":"Vân Hà Tinh","aliases":["Vọng Nguyệt"],"cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Tinh cầu thực chất là thân thể của Vọng Nguyệt, hiện bị sương mù và xúc tu bao phủ.","detail":"Vương Lâm tới đây để tìm Kim Viêm quáng mạch trong xương Vọng Nguyệt; mặt đất đầy xúc tu đỏ sậm, bên trong có niêm dịch, tiên lực bất thường và nơi bài tiết hấp thu.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"suong-mu-van-ha-tinh","name":"Sương mù Vân Hà Tinh","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Lớp sương mù dày đặc quanh Vân Hà Tinh, cản thần thức và ẩn xúc tu tập kích.","detail":"Vương Lâm dùng Lôi Thú và Thất Tinh kiếm trận mở đường rất chậm, nhưng khi gần ra khỏi sương mù vẫn bị xúc tu tập kích và mất kiếm trận.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"long-dat-van-ha-tinh","name":"Lòng đất Vân Hà Tinh","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Không gian niêm dịch trong thân thể Vọng Nguyệt, nơi chứa xương và Kim Viêm quáng mạch.","detail":"Vương Lâm đi sâu vào đây, phát hiện dao động tiên lực bất thường và tạm dừng hấp thu xương để tìm nguy cơ tiềm ẩn.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"hang-dong-ben-trong-van-ha-tinh","name":"Hang động rộng bên trong Vân Hà Tinh","cn":"","capDo":"khac","parentId":"long-dat-van-ha-tinh","blurb":"Hang động nơi Tham Lang bị mắc kẹt trong đại đỉnh.","detail":"Vị trí này nằm trong nơi bài tiết của Vọng Nguyệt, có hồng vụ, chất bẩn tanh tưởi và điện quang phun ra từ vách động.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"noi-hap-thu-bai-tiet-vong-nguyet","name":"Nơi hấp thu bài tiết của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"long-dat-van-ha-tinh","blurb":"Khu vực bài tiết và hấp thu lại vật chất trong thân thể Vọng Nguyệt.","detail":"Tham Lang bị kẹt tại đây trong đại đỉnh; nơi này phun ra hồng vụ, vật dơ bẩn và điện quang sau khi xúc tu bị kích thích.","theLucLienQuan":[],"nguon":["@c0666"]},{"id":"xuong-cua-vong-nguyet","name":"Xương của Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Bộ xương bên trong thân thể Vọng Nguyệt, nơi Vương Lâm phát hiện khe lớn và sơn thạch mắc kẹt.","detail":"Khe trên xương gần như chặt đứt bộ xương, có niêm dịch khô, Kim Viêm thạch và sơn thạch của Tham Lang đã bị đồng hóa.","theLucLienQuan":[],"nguon":["@c0667"]},{"id":"bun-dat-trong-than-the-vong-nguyet","name":"Bùn đất trong thân thể Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Môi trường bùn đất trong thân thể Vọng Nguyệt, nơi con Vọng Nguyệt nhỏ ẩn nấp.","detail":"Vương Lâm dùng thần thông chạy trốn xuyên vào bùn đất sau khi đoạt sơn thạch và bị phục kích.","theLucLienQuan":[],"nguon":["@c0667"]},{"id":"cho-bi-son-thach-tap-tru","name":"Chỗ bị sơn thạch tạp trụ","cn":"","capDo":"khac","parentId":"xuong-cua-vong-nguyet","blurb":"Vị trí xương Vọng Nguyệt từng bị sơn thạch của Tham Lang kẹt vào.","detail":"Vương Lâm quay lại nơi này sau khi rời khu bài tiết, quan sát an toàn rồi ngồi xuống kích hoạt lạc ấn Thăng Tiên quả và thi triển Hoàng Tuyền lực.","theLucLienQuan":[],"nguon":["@c0668"]},{"id":"trieu-tich-tham-uyen","name":"Triều tịch thâm uyên","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Nơi gắn với cảm ngộ Hoàng Tuyền lực của Vương Lâm.","detail":"Được nhắc như nguồn cảm ngộ đệ tam thức, liên hệ lực lượng thiên địa vô hình sinh ra khi hai tinh vực giao thoa.","theLucLienQuan":[],"nguon":["@c0668"]},{"id":"tinh-khong-vo-tan","name":"Tinh không vô tận","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Khoảng không bên ngoài Vân Hà Tinh, là đích thoát thân của Vương Lâm và Tiên Vệ sau khi xuyên qua tầng sương mù. Trong chương 670, nó được mở lộ khi sương mù lâu năm tiêu tán.","detail":"Sau khi Cấm Phiên và Thất Tinh Kiếm Trận bị hy sinh để tranh thủ từng khoảnh khắc, Vương Lâm cùng Tiên Vệ lao qua tầng sương mù hướng tới bầu trời bên ngoài. Khi sương mù Vân Hà Tinh tiêu tán, tinh không vô tận trở thành con đường sống trước cuộc truy đuổi của Vọng Nguyệt.","theLucLienQuan":[],"nguon":["@c0670"]},{"id":"co-the-vong-nguyet","name":"Cơ thể Vọng Nguyệt","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Không gian địa thể thực chất của Vân Hà Tinh, nơi mặt đất là thân thể Vọng Nguyệt.","detail":"Khi Vọng Nguyệt thức tỉnh, khe nứt khổng lồ mở ra như miệng lớn, bên trong có Thất Tinh Kiếm Trận tự bạo và khu vực bài tiết, hấp thu nơi Tham Lang tìm được đường thoát. Sự xoay mình của cơ thể này khiến lục địa bám trên thân Vọng Nguyệt vỡ vụn và sương mù lâu năm tiêu tán.","theLucLienQuan":[],"nguon":["@c0671"]},{"id":"tinh-khong-quanh-van-ha-tinh","name":"Tinh không quanh Vân Hà Tinh","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Vùng tinh không nơi Vương Lâm bỏ chạy và Vọng Nguyệt triển khai truy sát.","detail":"Sau khi lao khỏi Vân Hà Tinh, Vương Lâm dùng Tinh La Bàn mang xương Vọng Nguyệt chạy trong tinh không quanh đó. Đây cũng là nơi đàn Vọng Nguyệt nhỏ xuất hiện, Tham Lang dùng cự đỉnh và bình phong Sơn Hà Đồ, còn một chỉ Cổ Thần được huyễn hóa.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0672"]},{"id":"khe-nut-mieng-vong-nguyet","name":"Khe nứt miệng Vọng Nguyệt","cn":"","capDo":"khac","parentId":"co-the-vong-nguyet","blurb":"Lối mở trong cơ thể Vọng Nguyệt mà Tham Lang nhiều lần cố lao qua để thoát thân.","detail":"Khe nứt mở ra khi Vọng Nguyệt nuốt nửa xương, trở thành cơ hội thoát thân của Tham Lang. Tuy nhiên khe nứt nhiều lần khép lại hoặc bị biến cố cản trở, khiến hắn tiếp tục rơi vào hiểm cảnh.","theLucLienQuan":[],"nguon":["@c0672"]},{"id":"tinh-khong-noi-vong-nguyet-thuc-tinh","name":"Tinh không nơi Vọng Nguyệt thức tỉnh","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Chiến trường chính của chương, nơi Vương Lâm, Tham Lang và Vọng Nguyệt giao phong sau khi cự thú thức tỉnh.","detail":"Khu vực tinh không này là nơi bình phong Sơn Hà Đồ trôi nổi, Tham Lang dùng Tôn Tiên Đế Quan chống Cổ Thần Chỉ, Vương Lâm bị phá hủy nhục thân rồi nguyên thần hóa thái cổ Lôi Long bỏ chạy. Vọng Nguyệt tiếp tục truy đuổi từ đây sau khi Cổ Thần Chỉ tiêu tán.","theLucLienQuan":[],"nguon":["@c0673"]},{"id":"phuong-xa-trong-tinh-khong","name":"Phương xa trong tinh không","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Vị trí vương miện của Tham Lang trôi nổi sau khi hắn bị Cổ Thần Chỉ đánh bay.","detail":"Trong lúc nguyên thần Vương Lâm bỏ chạy, hắn phát hiện Tôn Tiên Đế Quan trôi ở phương xa trong tinh không, dùng thần thức thu lấy rồi tiếp tục đào thoát không quay đầu.","theLucLienQuan":[],"nguon":["@c0673"]},{"id":"la-thien-nam-vuc","name":"La Thiên Nam Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Một đại vực của La Thiên, nằm đối ứng với La Thiên Bắc Vực; Vương Lâm chạy sang đây sau khi thoát khỏi Vọng Nguyệt.","detail":"La Thiên Nam Vực là khu vực Vương Lâm tiến vào trong cuộc đào thoát khỏi Vọng Nguyệt. Khi đến ranh giới giữa Nam Vực và Bắc Vực, Vọng Nguyệt dừng lại không dám vượt qua, khiến Vương Lâm nghi ngờ nơi này tồn tại điều gì đó làm dị thú kiêng kỵ. Trong Nam Vực, hắn cảm ứng được khu vực tầng đá che giấu một tiểu tinh cầu lôi điện thích hợp để chữa thương và tái tạo thân thể.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"ranh-gioi-la-thien-nam-bac-vuc","name":"Ranh giới La Thiên Nam-Bắc Vực","cn":"","capDo":"khac","parentId":null,"blurb":"Đường phân cách giữa La Thiên Bắc Vực và La Thiên Nam Vực, nơi Vọng Nguyệt dừng truy sát Vương Lâm.","detail":"Ranh giới La Thiên Nam-Bắc Vực là điểm mấu chốt trong cuộc truy đuổi của Vọng Nguyệt. Vương Lâm vượt qua khu vực này sang Nam Vực, còn Vọng Nguyệt vì ký ức cảnh cáo mơ hồ và cảm giác khủng hoảng nên không dám tiếp tục, từ đó giúp Vương Lâm thoát khỏi tử cục.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"tinh-cau-loi-quang-loi-nguc","name":"Tinh cầu lôi quang / Lôi Ngục","cn":"","capDo":"tinh-cau","parentId":"la-thien-nam-vuc","blurb":"Tiểu tinh cầu bỏ hoang trong La Thiên Nam Vực, bị tầng đá che phủ và tràn đầy lôi điện tiên thiên.","detail":"Tinh cầu lôi quang, còn được gọi là Lôi Ngục, là một tiểu tinh cầu bỏ hoang ẩn sau tầng đá dày đặc ở La Thiên Nam Vực. Nơi này không có sinh linh, không có linh khí, nhưng sinh cơ nồng đậm và tràn ngập lôi quang tự nhiên do trời đất sinh ra. Vương Lâm chọn nơi đây làm động phủ tạm thời, dùng lôi lực để khôi phục nguyên thần trong mười năm, rồi mượn Cổ Thần Quyết và lôi điện toàn tinh cầu để bắt đầu ngưng tụ lại thân thể.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"tang-da-bao-quanh-tinh-cau-loi-quang","name":"Tầng đá bao quanh tinh cầu lôi quang","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Lớp đá dày đặc che giấu tiểu tinh cầu lôi quang bên trong La Thiên Nam Vực.","detail":"Tầng đá bao quanh tinh cầu lôi quang dày đặc như một bức tường thiên nhiên, khiến thần thức khó dò xét sâu vào bên trong. Vương Lâm để Tiên Vệ xuyên qua trước, nhờ đó phát hiện tiểu tinh cầu bỏ hoang tràn đầy lôi điện ở phía trong. Về sau hắn còn cảm thấy nơi khiến mình dễ chịu hơn có thể nằm sâu hơn trong tầng đá này.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"tinh-cau-nguyen-thuy-la-thien-bac-vuc","name":"Tinh cầu nguyên thủy ở La Thiên Bắc Vực","cn":"","capDo":"tinh-cau","parentId":"la-thien-bac-vuc","blurb":"Một tinh cầu nguyên thủy trong La Thiên Bắc Vực, nơi Tham Lang rơi xuống và ẩn vào lòng đất.","detail":"Tinh cầu nguyên thủy ở La Thiên Bắc Vực có linh khí không đậm nhưng có phàm nhân cư trú. Tham Lang rơi xuống vùng đồng bằng phía bắc của tinh cầu này trong tình trạng thân thể vỡ nát, nguyên thần hao tổn nặng, sau đó chìm xuống lòng đất để chờ ngày khôi phục. Từ đó phàm nhân trên tinh cầu thường ngửi thấy mùi tanh mơ hồ như phát ra từ dưới đất.","theLucLienQuan":["Phàm nhân trên tinh cầu nguyên thủy"],"nguon":["@c0674"]},{"id":"loi-tri-tren-tinh-cau-loi-quang","name":"Lôi Trì trên tinh cầu lôi quang","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Khu vực mặt đất trên tinh cầu lôi quang hấp thu và phóng thích lôi điện như ao sấm.","detail":"Lôi Trì trên tinh cầu lôi quang là nơi lôi điện tụ tập dày đặc trên mặt đất, liên tục hấp thu và phóng thích lôi lực. Vương Lâm ngồi trong lôi quang để khôi phục nguyên thần, rồi dẫn lôi lực từ Lôi Trì nhập vào nguyên thần, ngưng tụ xương tay, xương ngón và dần hình thành khung xương mới.","theLucLienQuan":[],"nguon":["@c0674"]},{"id":"day-nui-do-xuong-mat-trang-hoa-thanh","name":"Dãy núi do xương mặt trăng hóa thành","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Dãy núi giống Thần Long nằm sấp trên tinh cầu lôi quang, do xương mặt trăng hóa thành. Bên trong chứa Kim Viên Quáng để Thiên Nghịch hấp thu.","detail":"Vương Lâm đặt Thiên Nghịch Châu lên dãy núi này để hấp thu thuộc tính kim. Kim Viên Quáng trong xương hóa thành tơ vàng bị hạt châu hút dần, sau ba tháng bị hấp thu hết, chỉ còn lại một tòa núi đá.","theLucLienQuan":[],"nguon":["@c0675"]},{"id":"vung-dat-yeu-linh","name":"Vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng đất được nhắc lại trong hồi tưởng của Vương Lâm về lần đối mặt Thiên Kiếp khi tiến lên Vấn Đỉnh.","detail":"Trong lúc đứng trước cánh cửa tím của Thiên Nghịch, Vương Lâm nhớ lại cảm giác khi từng đối mặt Thiên Kiếp ở vùng đất Yêu Linh để so sánh với nỗi sợ bản năng hiện tại.","theLucLienQuan":[],"nguon":["@c0676"]},{"id":"nui-hang-nhac-phai","name":"Núi Hằng Nhạc Phái","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm trong hồi ức thời thiếu niên của Vương Lâm. Nơi này gắn với cảm giác kính sợ ban đầu của hắn trước môn phái tu tiên.","detail":"Khi nhìn cánh cửa tím khổng lồ, Vương Lâm nhớ lại thời còn là thiếu niên phàm nhân, đứng trên núi nhìn Hằng Nhạc Phái nguy nga và vẫn kiên định leo lên dù toàn thân đổ máu.","theLucLienQuan":["Hằng Nhạc Phái"],"nguon":["@c0676"]},{"id":"canh-cua-mau-tim","name":"Cánh cửa màu tím","cn":"","capDo":"khac","parentId":"tinh-cau-loi-quang-loi-nguc","blurb":"Dị tượng khổng lồ xuất hiện sau khi Thiên Nghịch ngũ hành viên mãn. Cánh cửa đứng giữa thiên địa và có cánh tay tử quang vẫy gọi Vương Lâm.","detail":"Sau khi Hạt Châu Thiên Nghịch phóng xuất hơn phân nửa lực ngũ hành tích lũy, một cánh cửa màu tím hiện ra giữa thiên địa. Nó không phát uy áp rõ rệt nhưng khiến Vương Lâm sinh nỗi sợ từ linh hồn; bên ngoài cửa, tử quang ngưng tụ thành cánh tay khổng lồ, vừa vẫy gọi vừa có thể nhẹ nhàng phá hủy xương Vọng Nguyệt và xé nát không gian quanh tinh cầu.","theLucLienQuan":[],"nguon":["@c0676"]},{"id":"canh-cua-thien-dia","name":"Cánh cửa thiên địa","cn":"","capDo":"khac","parentId":null,"blurb":"Cánh cửa khổng lồ xuất hiện cùng cánh tay bí ẩn trong biến cố Thiên Nghịch. Nó tan biến sau khi cánh tay vẫy gọi Vương Lâm.","detail":"Cánh cửa thiên địa là nơi cánh tay khổng lồ vươn ra, thể hiện loại quy tắc khiến Vương Lâm kinh sợ. Sau khi cánh tay cùng cánh cửa biến mất, tử quang co lại thành Thiên Nghịch Châu, để lại nghi vấn về nơi cánh cửa thông tới và các chủ nhân Thiên Nghịch trước kia.","theLucLienQuan":[],"nguon":["@c0677"]},{"id":"tien-vuc-vien-co","name":"Tiên vực viễn cổ","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Không gian được Vương Lâm nêu như giả thuyết về đích đến của cánh cửa thiên địa. Chương này chưa xác nhận cánh cửa thật sự thông tới nơi đó.","detail":"Khi suy đoán về lai lịch Thiên Nghịch và cánh cửa sau khi ngũ hành viên mãn, Vương Lâm nghĩ tới khả năng cánh cửa liên quan đến tiên vực viễn cổ. Đây chỉ là nghi vấn trong dòng suy luận của hắn, chưa có kết luận chắc chắn.","theLucLienQuan":["Tiên Vực thời viễn cổ"],"nguon":["@c0677"]},{"id":"tang-da-vun-nam-vuc-la-thien","name":"Tầng đá vụn Nam Vực La Thiên","cn":"","capDo":"khac","parentId":"la-thien-nam-vuc","blurb":"Khu vực tầng đá vụn ở Nam Vực La Thiên, gắn với truyền thuyết nơi Thiên Nghịch lần đầu xuất hiện.","detail":"Nơi này được đồn là địa phương hạt châu Thiên Nghịch thần bí lần đầu hiện thế năm xưa. Sự xuất hiện ấy gây ra dị biến Lôi Đình, khiến khu vực dần trở thành Lôi Ngục thích hợp cho tu sĩ tu luyện thần thông Lôi hệ và hấp thụ nguyên lực.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0678"]},{"id":"khong-gian-thien-nghich","name":"Không gian Thiên Nghịch","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian hỗn độn vô biên bên trong cánh cửa Thiên Địa do Thiên Nghịch mở ra. Đây là nơi Vương Lâm chứng kiến vật sáng sinh diệt thành tinh cầu và bước vào trạng thái truy tìm Đạo.","detail":"Sau khi tâm thần bị hút qua khe cửa, Vương Lâm nhận ra nơi này là không gian Thiên Nghịch. Trong không gian ấy, những vật sáng bành trướng thành tinh cầu có đại lục, sông biển, linh khí rồi lại thoái hóa về vật sáng, khiến hắn chìm sâu vào cảm ngộ sinh diệt và truy tìm dấu chân của Đạo.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"tinh-cau-do-vat-sang-hoa-thanh","name":"Tinh cầu do vật sáng hóa thành","cn":"","capDo":"tinh-cau","parentId":"khong-gian-thien-nghich","blurb":"Các vật sáng trong không gian Thiên Nghịch bành trướng thành tinh cầu rồi lại thoái hóa. Chúng là cảnh tượng then chốt khiến Vương Lâm quan sát sinh diệt và lần theo lực lượng thần bí phía sau.","detail":"Những vật sáng trong không gian Thiên Nghịch hóa thành tinh cầu có đại lục, sông biển và linh khí nồng đậm, sau đó biến đổi ngược về vật sáng như thời gian đảo chiều. Quá trình lặp lại này khiến tâm thần Vương Lâm dần chìm vào trạng thái quên hết mọi sự.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"ba-tinh-cau-am-ap","name":"Ba tinh cầu ấm áp","cn":"","capDo":"tinh-cau","parentId":"khong-gian-thien-nghich","blurb":"Một tinh cầu tự nhiên có sức sống yếu nhưng ấm áp, kèm hai tinh cầu nhỏ bên cạnh mang khí tức quyến luyến. Sau khi Vương Lâm chạm vào hư vô, cả ba hóa thành hào quang nhập vào đầu hắn.","detail":"Ba tinh cầu này khác với những vật sáng sinh diệt thông thường trong không gian Thiên Nghịch: một tinh cầu có hơi ấm yếu ớt, hai tinh cầu nhỏ ở gần tỏa cảm giác quyến luyến. Khi Vương Lâm chạm nhẹ hư vô, chúng tiêu tan thành ba đạo hào quang dung nhập vào đầu hắn, khiến hắn dừng việc truy tìm và bước sang trạng thái hóa thành vật sáng.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"tinh-cau-sau-khi-vuong-lam-hoa-thanh-vat-sang","name":"Tinh cầu sau khi Vương Lâm hóa thành vật sáng","cn":"","capDo":"tinh-cau","parentId":"khong-gian-thien-nghich","blurb":"Tinh cầu do chính trạng thái vô thức của Vương Lâm hóa thành sau khi ba luồng hào quang nhập vào đầu hắn. Nơi này có núi sông, biển cả, thôn trang phàm nhân, một hộ gia đình phía bắc và cô gái áo trắng phía nam.","detail":"Sau khi Vương Lâm hóa thành vật sáng và hấp thu bụi bặm xung quanh, một tinh cầu dần hình thành với núi non, sông suối, biển cả và đời sống phàm tục. Trên tinh cầu ấy, một nam một nữ sống ở phía bắc, cô gái áo trắng xuất hiện phía nam; qua vô số năm tháng, ba người này là điều duy nhất không biến mất.","theLucLienQuan":[],"nguon":["@c0679"]},{"id":"vu-tien-gioi","name":"Vũ Tiên Giới","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Vũ Tiên Giới là tiên giới Vương Lâm từng vào trước đây, được hắn đem so sánh với Lôi Tiên Giới. Khi ở Vũ Tiên Giới, hắn chưa thể hấp thụ tiên ngọc như hiện tại.","detail":"Trong lúc nghe tin Lôi Tiên Giới sắp mở, Vương Lâm nhớ tới lần từng vào Vũ Tiên Giới. Sự khác biệt là khi đó hắn chưa đủ khả năng hấp thụ tiên ngọc, còn hiện tại Lôi Tiên Giới có thể trở thành cơ hội giúp tu vi viên mãn.","theLucLienQuan":["Tứ đại tiên giới Phong, Vũ, Lôi, Điện"],"nguon":["@c0681","@c0696"]},{"id":"trung-tam-loi-tri","name":"Trung tâm Lôi Trì","cn":"","capDo":"khac","parentId":"loi-tri-tren-tinh-cau-loi-quang","blurb":"Trung tâm Lôi Trì là khu vực Vương Lâm hướng tới sau hai năm tu luyện vì lôi đình nơi đó mạnh hơn nhiều so với vùng ngoài.","detail":"Vương Lâm nhận ra càng gần trung tâm Lôi Trì thì lôi đình càng mạnh và nguyên lực ẩn chứa càng nhiều; một đạo lôi đình gần trung tâm được nhận định vượt xa trăm đạo ở ngoài rìa, nên hắn quyết định tiến sâu hơn để tăng tốc khôi phục nguyên lực.","theLucLienQuan":[],"nguon":["@c0682"]},{"id":"thien-dia-dai-mon","name":"Thiên Địa Đại Môn","cn":"","capDo":"khac","parentId":null,"blurb":"Mốc không gian được nhắc lại trong liên tưởng của Vương Lâm khi cảm ngộ Lôi Trì.","detail":"Vương Lâm từng ở ngoài Thiên Địa Đại Môn và nhìn qua khe hở vào không gian Nghịch Thiên. Trải nghiệm đó được dùng để so sánh với trạng thái quên thân, chỉ còn quan sát bản chất kỳ dị của Lôi Trì.","theLucLienQuan":[],"nguon":["@c0683"]},{"id":"loi-tri","name":"Lôi Trì","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Không gian lôi đình nơi Vương Lâm tu luyện và nơi Thân Công Hổ đối đầu Chiến Không Liệt.","detail":"Lôi Trì có lôi đình dày đặc, càng vào vòng trong thì thiên địa nguyên lực càng khổng lồ. Chương này diễn ra tại khu vực Lôi Trì, khi Vương Lâm thổ nạp lôi đình còn Thân Công Hổ và Chiến Không Liệt chuẩn bị giao chiến bên ngoài phạm vi hắn đang ngồi.","theLucLienQuan":["Lôi Tiên Điện","Gia tộc Thân Công","Chiến gia"],"nguon":["@c0684"]},{"id":"vong-trong-loi-tri","name":"Vòng trong Lôi Trì","cn":"","capDo":"khac","parentId":"loi-tri","blurb":"Khu vực sâu trong Lôi Trì nơi Vương Lâm tỉnh lại và tiếp tục thổ nạp lôi đình.","detail":"Vòng trong Lôi Trì có lôi đình nồng đậm hơn ngoài rìa rất nhiều. Vương Lâm tỉnh lại tại đây, vẫn còn cách trung tâm rất xa, nhưng vị trí ấy đã vượt quá khả năng tiến vào của Chiến Không Liệt với tu vi Dương Thực viên mãn, khiến hắn sinh nghi.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0684"]},{"id":"noi-hoang-da-o-la-thien-tinh-vuc","name":"Nơi hoang dã ở La Thiên Tinh Vực","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực Vương Lâm chọn tìm đến sau khi rời Lôi Trì. Nơi này phần lớn là tinh cầu bỏ hoang, ít tu sĩ qua lại, nhưng vẫn có một số tinh cầu có phàm nhân và gia tộc tu chân bậc thấp.","detail":"Theo tinh đồ trong ngọc giản của Thân Công Hổ, Vương Lâm chọn vùng hoang dã ở La Thiên Tinh Vực để tìm nơi bí mật tu luyện. Khu vực này ít bị tu sĩ chú ý, phù hợp với mục tiêu tăng tu vi, chỉnh lý thần thông và chuẩn bị cho Lôi Tiên Giới.","theLucLienQuan":[],"nguon":["@c0686"]},{"id":"tinh-cau-bo-hoang-giong-chu-tuoc-tinh","name":"Tinh cầu bỏ hoang giống Chu Tước Tinh","cn":"","capDo":"tinh-cau","parentId":"noi-hoang-da-o-la-thien-tinh-vuc","blurb":"Tinh cầu có sự sống khiến Vương Lâm nhớ tới Chu Tước Tinh vì cảm giác và hơi thở tương tự. Đây là nơi hắn chọn tiến vào sau khi rời Lôi Trì.","detail":"Tinh cầu này nằm trong vùng hoang dã của La Thiên Tinh Vực, có phàm nhân sinh sống và tu sĩ cấp thấp. Cảm giác giống Chu Tước Tinh khiến Vương Lâm nhớ quê cũ, từ đó quyết định đi vào và cuối cùng chọn Thanh Linh Tinh, Hoành Vân Phong làm điểm dừng chân.","theLucLienQuan":["Trương gia"],"nguon":["@c0686"]},{"id":"thanh-linh-tinh","name":"Thanh Linh Tinh","cn":"","capDo":"tinh-cau","parentId":"noi-hoang-da-o-la-thien-tinh-vuc","blurb":"Tinh cầu màu xanh nước biển, biển chiếm hơn phân nửa và sức sống dày đặc. Trên tinh cầu có nhiều quốc gia phàm nhân, gia tộc tu chân, nhưng tu sĩ cao nhất chỉ đến Nguyên Anh.","detail":"Thanh Linh Tinh là nơi Vương Lâm đặt chân sau khi rời Lôi Trì và tìm một tu chân tinh thuộc về mình tại La Thiên Tinh Vực. Tinh cầu này gợi cảm giác giống Chu Tước Tinh, có sinh cơ mạnh, nhiều phàm nhân và thế lực tu chân cấp thấp, trong đó Trương gia là gia tộc nổi bật.","theLucLienQuan":["Trương gia"],"nguon":["@c0686","@c0698"]},{"id":"hoanh-van-phong","name":"Hoành Vân Phong","cn":"","aliases":["Hoành Vân Sơn Phong"],"capDo":"khac","parentId":"thanh-linh-tinh","blurb":"Ngọn núi cao nhất trên Thanh Linh Tinh, thuộc địa bàn Trương gia. Đây là nơi tộc nhân Nguyên Anh đại viên mãn của Trương gia thường lên bế quan tọa hóa trước khi hết thọ nguyên.","detail":"Hoành Vân Phong có linh khí loãng nhưng địa thế hùng vĩ, là biểu tượng trọng yếu trên Thanh Linh Tinh. Vương Lâm chọn nơi này làm điểm dừng chân; cùng lúc đó, Trương Tân Hải lên đỉnh núi chuẩn bị tọa hóa và kinh sợ khi thấy Vương Lâm đứng trên thạch đài mà thần thức không phát hiện được.","theLucLienQuan":["Trương gia"],"nguon":["@c0686"]},{"id":"vung-quanh-ngon-nui-hoanh-van-phong","name":"Vùng quanh ngọn núi trong phạm vi ngàn dặm vạn dặm","cn":"","capDo":"khac","parentId":"hoanh-van-phong","blurb":"Khu vực quanh Hoành Vân Phong nơi Vương Lâm cho Hứa Lập Quốc hoạt động có giới hạn.","detail":"Vương Lâm cho Hứa Lập Quốc tạm thời không phải quay lại túi trữ vật, được hoạt động và lĩnh ngộ viễn cổ kiếm ý trong phạm vi quanh ngọn núi; về sau Hứa Lập Quốc cũng dùng khu vực này để lừa vài tu sĩ qua đường.","theLucLienQuan":["Trương gia"],"nguon":["@c0689"]},{"id":"man-suong-den-quanh-ngon-nui","name":"Màn sương đen quanh ngọn núi","cn":"","capDo":"khac","parentId":"hoanh-van-phong","blurb":"Màn sương đen quanh Hoành Vân Phong là nơi Hứa Lập Quốc ẩn nấp và trêu chọc người tới cầu kiến.","detail":"Cha con Trương Tân Hải kiêng kị màn sương đen quanh ngọn núi; Hứa Lập Quốc ẩn trong đó, dụ con trai Trương Tân Hải tiến vào và định tạm dung nhập thân thể người này.","theLucLienQuan":["Trương gia"],"nguon":["@c0689"]},{"id":"hoang-mac-tay-bac-thanh-linh-tinh","name":"Hoang mạc tây bắc Thanh Linh Tinh","cn":"","capDo":"khac","parentId":"thanh-linh-tinh","blurb":"Hoang mạc nơi Vương Lâm bố trí trận pháp tiên ngọc để trùng kích Vấn Đỉnh viên mãn.","detail":"Ở hoang mạc tây bắc Thanh Linh Tinh, Vương Lâm bày lượng lớn tiên ngọc thành trận pháp khổng lồ, thổ nạp tiên khí trong một năm rồi uống tiên dịch để tiến tới Vấn Đỉnh viên mãn.","theLucLienQuan":[],"nguon":["@c0689"]},{"id":"thanh-dan-tinh","name":"Thánh Đàn Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tu chân tinh nơi Vương Lâm chờ đoạt Lôi Đỉnh từ đội tu sĩ trở về.","detail":"Theo ngọc giản của Thân Công Hổ, nơi này có hai gia tộc thường nhận nhiều Lôi Đỉnh. Vương Lâm đến đây, dùng thần thức kiểm tra rồi ngồi chờ trong tinh không cho tới khi đội tu sĩ trở về.","theLucLienQuan":["Trương gia","Hai gia tộc tu chân trên Thánh Đàn Tinh"],"nguon":["@c0690"]},{"id":"tu-chan-tinh-cua-lao-gia","name":"Tu chân tinh của lão già","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu nơi lão già Âm Hư và tộc nhân trở về sau giao dịch.","detail":"Sau khi đổi được ba thuật của Vương Lâm, lão già trở về tinh cầu này và lập tức bế quan để chuẩn bị một tháng sau tới Lôi Tiên Giới.","theLucLienQuan":["Gia tộc của lão già Âm Hư"],"nguon":["@c0691"]},{"id":"cua-lon-loi-tien-gioi","name":"Cửa lớn Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Đích đến của các tu sĩ được lôi quang dẫn dắt khi Lôi Tiên Giới mở.","detail":"Sau khi Lôi Đỉnh vỡ, cuồng lôi cuốn Vương Lâm qua không gian dẫn tới cửa này với tốc độ vượt xa tu sĩ bình thường.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0692"]},{"id":"hu-khong-tren-duong-toi-loi-tien-gioi","name":"Hư không trên đường tới Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Không gian dẫn dắt tu sĩ tới Lôi Tiên Giới bằng lôi quang.","detail":"Tại đây, Vương Lâm bị cuồng lôi cuốn đi nhanh đến mức không dám tản thần thức, còn nhiều tu sĩ khác chỉ thấy một luồng sao băng lôi đình lao qua.","theLucLienQuan":["La Thiên Tinh Vực"],"nguon":["@c0692"]},{"id":"cua-loi-tien-gioi","name":"Cửa Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Lối vào Lôi Tiên Giới, bản chất là một đạo sấm sét đỏ sậm khổng lồ.","detail":"Cửa này nằm ở tận cùng không gian hư vô, không phải cổng vật chất. Truyền thuyết nói toàn bộ tiên hồn của Lôi Tiên Giới sau khi sụp đổ hóa thành đạo sấm sét đỏ sậm này.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0693"]},{"id":"khong-gian-hu-vo-truoc-loi-tien-gioi","name":"Không gian hư vô trước Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực các tu sĩ khoanh chân chờ trước cửa Lôi Tiên Giới.","detail":"Nhiều sứ giả Lôi Tiên Điện, độc tu và tu sĩ bước thứ hai tụ tập ở đây chờ Lôi Tiên Giới mở. Sao băng lôi đình của Vương Lâm lao qua khu vực này trước khi cửa mở.","theLucLienQuan":["Lôi Tiên Điện","Độc tu La Thiên Tinh Vực"],"nguon":["@c0693"]},{"id":"thien-la-tinh-vuc","name":"Thiên La Tinh Vực","cn":"","capDo":"vuc","parentId":"tinh-khong","blurb":"Tinh vực lưu truyền nhiều truyền thuyết về Lôi Tiên Giới.","detail":"Một truyền thuyết được nhiều người chấp nhận tại đây cho rằng cửa Lôi Tiên Giới do toàn bộ tiên hồn sau khi tiên giới sụp đổ hóa thành.","theLucLienQuan":[],"nguon":["@c0693"]},{"id":"ngon-loi-son-den-trong-loi-tien-gioi","name":"Ngọn lôi sơn đen trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi đen trên phần đại lục bị phá hủy trong Lôi Tiên Giới, có vô số cuồng lôi chạy qua.","detail":"Lão già tóc bạc xuất hiện tại đây trước khi Lôi Tiên Giới mở, cảm ứng dị biến rồi hóa thành vô số tinh điểm biến mất.","theLucLienQuan":[],"nguon":["@c0693"]},{"id":"dai-luc-phia-dong-trong-loi-tien-gioi","name":"Đại lục phía đông trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực nơi lưu tinh lôi đình nện Vương Lâm xuống, tạo hố sâu và làm địa tầng bất ổn.","detail":"Sau cú va chạm, mặt đất sụp xuống và chôn vùi Vương Lâm vào khu vực thạch thất dưới lòng đất, mở đầu tuyến giam cầm do lão giả tóc bạc can thiệp.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"thach-that-duoi-long-dat","name":"Thạch thất dưới lòng đất","cn":"","capDo":"khac","parentId":"dai-luc-phia-dong-trong-loi-tien-gioi","blurb":"Nơi Vương Lâm tỉnh lại sau khi bị vùi lấp trong Lôi Tiên Giới.","detail":"Thạch thất đã sụp đổ, xung quanh bị bùn đất chứa thiên địa nguyên lực phong tỏa. Vương Lâm thổ nạp tại đây, gọi khôi lỗi Tiên Vệ hộ pháp rồi phát hiện chỉ có phía trước có thể mở đường.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"thong-dao-duoi-long-dat","name":"Thông đạo dưới lòng đất","cn":"","capDo":"khac","parentId":"dai-luc-phia-dong-trong-loi-tien-gioi","blurb":"Lối đi quanh co phía trước thạch thất, dường như bị người khác điều khiển.","detail":"Vương Lâm dùng tiên lực hóa thành quái phong mở đường. Trong lúc dò xét, các cửa ra thông lên mặt đất liên tục lóe sáng rồi biến mất trước khi hắn tới nơi.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"hu-khong-ben-ngoai-thong-dao","name":"Hư không bên ngoài thông đạo","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khoảng hư không mà Vương Lâm lao vào sau khi vượt qua cánh cửa kế tiếp trong mạng thần thông dưới lòng đất. Đây là khu vực bên ngoài hệ thống thông đạo giam khốn tại Lôi Tiên Giới.","detail":"Sau khi thông đạo dưới lòng đất bị phá sập, cửa ra vẫn tiếp tục xuất hiện tại điểm giao thiên địa nguyên lực. Vương Lâm lợi dụng việc không còn bùn đất cản trở để cùng Tiên Vệ và Lôi Thú lao qua cửa, thoát khỏi khu vực bị nhốt và bay vào hư không bên ngoài.","theLucLienQuan":[],"nguon":["@c0695"]},{"id":"manh-dai-luc-nho-cua-loi-tien-gioi","name":"Một mảnh đại lục nhỏ của Lôi tiên giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Một mảnh đại lục nhỏ trong Lôi tiên giới là nơi lão giả tóc trắng đứng trước ngọn núi lớn để tiếp tục kế hoạch. Tại đây ông chuẩn bị thu hồn tiên sơn và bố trí La Thiên đại trận.","detail":"Sau khi nhận ra Vương Lâm đã thoát sớm bằng mánh khóe, lão giả tóc trắng vẫn ở lại trên mảnh đại lục nhỏ này. Ông đặt trọng tâm vào ngọn núi lớn cao vút trong mây, coi việc thu hồn tiên sơn là bước trước khi bố trí La Thiên đại trận.","theLucLienQuan":["La Thiên"],"nguon":["@c0696"]},{"id":"tien-son","name":"Tiên sơn","cn":"","aliases":["Ngọn núi lớn cao vút trong mây"],"capDo":"khac","parentId":"manh-dai-luc-nho-cua-loi-tien-gioi","blurb":"Tiên sơn là ngọn núi lớn cao vút trong mây mà lão giả tóc trắng muốn thu hồn. Hồn của nó liên quan trực tiếp tới việc bố trí La Thiên đại trận.","detail":"Lão giả tóc trắng đặt mục tiêu thu được hồn của tiên sơn trước khi bố trí La Thiên đại trận. Đây là mắt xích quan trọng trong kế hoạch ông đã chuẩn bị suốt mấy vạn năm.","theLucLienQuan":["La Thiên"],"nguon":["@c0696"]},{"id":"dai-luc-manh-vo-trong-loi-tien-gioi","name":"Đại lục mảnh vỡ trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mảnh đại lục rộng lớn trong Lôi Tiên Giới, nơi Vương Lâm giao chiến và rời xa chiến trường.","detail":"Mảnh đại lục này rất rộng và vững chắc. Sau trận với Hứa Phong Hàn, Vương Lâm rời khỏi khu vực giao chiến nhiều vạn dặm, tiếp tục bay tới gần rìa đại lục để tìm nơi dưỡng thương.","theLucLienQuan":[],"nguon":["@c0699"]},{"id":"loi-son","name":"Lôi Sơn","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Ngọn núi gần rìa đại lục Lôi Tiên Giới, luôn lóe lôi quang.","detail":"Lôi Sơn có lôi đình giáng xuống và liên kết với núi. Vương Lâm chọn nơi này, khoét động phủ ở lưng chừng núi để thổ nạp, luyện hóa tiên lôi và nghiên cứu thu hoạch sau trận chiến.","theLucLienQuan":[],"nguon":["@c0699"]},{"id":"dong-phu-tren-loi-son","name":"Động phủ trên Lôi Sơn","cn":"","capDo":"khac","parentId":"loi-son","blurb":"Động phủ tạm thời do Vương Lâm mở trên lưng chừng Lôi Sơn.","detail":"Đây là nơi Vương Lâm dưỡng thương sau khi diệt Hứa Phong Hàn. Hắn luyện hóa hai đạo tiên lôi, nghiên cứu mảnh vỡ pháp bảo, kiểm tra Ma Liên và lấy được vật phẩm trong các quang châu.","theLucLienQuan":[],"nguon":["@c0699"]},{"id":"tinh-cau-do-sam-cua-dieu-gia","name":"Tinh cầu đỏ sậm của Diêu gia","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu lớn của Diêu gia trong La Thiên Tinh Vực, tỏa khí tức quỷ dị.","detail":"Diêu Không trở về tinh cầu đỏ sậm này để xin nhận tổ quy tông. Từ nơi đây vang ra giọng nói khàn khàn của tổ phụ Diêu gia, người tính ra Diêu Tích Huyết đang ở Lôi Tiên Giới.","theLucLienQuan":["Diêu gia"],"nguon":["@c0699"]},{"id":"nui-da-canh-cam-che","name":"Núi đá cạnh cấm chế","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Khu núi đá gần trận pháp cấm chế trên đại lục vỡ trong Lôi Tiên Giới. Đây là nơi gợn sóng không gian che giấu sự ẩn hiện của Lý Nguyên và nữ tu.","detail":"Bề ngoài núi đá bình thường, nhưng cạnh đó có khu vực gợn sóng không gian để hai tu sĩ ẩn nấp quan sát con mồi. Vương Lâm rời đi giả tạo rồi quay lại theo dõi, từ đó phát hiện hai người bước ra từ nơi ẩn giấu.","theLucLienQuan":["Gia tộc của nữ tu Vấn Đỉnh đại viên mãn"],"nguon":["@c0700"]},{"id":"cua-dong-duoi-cam-che","name":"Cửa động dưới cấm chế","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Hang động rộng vài trượng bị trận pháp cấm chế che giấu. Bên trong có bóng xanh hoặc thú cưng của nữ tu, có thể nuốt tu sĩ và kéo cả nguyên thần trở lại.","detail":"Cửa động chỉ lộ ra sau khi hình nhân mộc linh tự bạo phá lớp cấm chế bên ngoài. Tu sĩ trung niên vừa tiến vào đã gặp nạn, nguyên thần thoát ra cũng bị bóng xanh cuốn ngược vào trong, khiến nữ tu hưng phấn vì thú cưng đã ăn được một người.","theLucLienQuan":["Gia tộc của nữ tu Vấn Đỉnh đại viên mãn"],"nguon":["@c0700"]},{"id":"hang-dong-trong-tran-phap-cam-che","name":"Hang động trong trận pháp cấm chế","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Hang động nơi khí âm hàn xanh lục hóa thành Thiên Quỷ, nằm trong bố trí cấm chế của Lý Nguyên và Cát Hồng.","detail":"Sau khi phá tan mười tám cấm chế, Vương Lâm tiến vào hang và nhận ra khí âm hàn xanh lục bên trong chính là Thiên Quỷ. Đây là nơi đối phương dùng để mai phục nhưng cuối cùng Thiên Quỷ bị thu vào Tôn Hồn Phiên.","theLucLienQuan":["Cát gia"],"nguon":["@c0701"]},{"id":"bi-dia-co-cam-che-trong-loi-tien-gioi","name":"Bí địa có cấm chế trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Nơi bí ẩn do bản đồ cổ của Lý Nguyên chỉ dẫn, được cho là còn cấm chế và vật bảo tồn nguyên vẹn.","detail":"Lý Nguyên dùng tin tức về bí địa này để chuộc lỗi với Vương Lâm. Theo lời hắn, nơi đó tồn tại từ trước khi Lôi Tiên Giới sụp đổ, có cấm chế bao phủ, có nguyên khí và có thể còn tiên bảo hoặc vật chưa bị phá hủy.","theLucLienQuan":[],"nguon":["@c0701"]},{"id":"ria-dai-luc-loi-tien-gioi","name":"Rìa đại lục Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Mép mảnh đại lục bị xé rách, phía dưới là hư vô và phía ngoài có các sợi xích lôi quang kéo dài.","detail":"Sau vài ngày bay, ba người tới rìa đại lục. Từ đây có thể nhìn thấy khoảng hư vô tối đen và các đạo lôi quang như xích sắt nối sang những mảnh đại lục khác trong Lôi Tiên Giới.","theLucLienQuan":[],"nguon":["@c0701"]},{"id":"soi-xich-loi-quang","name":"Sợi xích lôi quang","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Những đạo lôi quang nối các mảnh đại lục vỡ của Lôi Tiên Giới, vừa là đường định hướng vừa chứa lôi đình mạnh mẽ.","detail":"Tu sĩ đi trong hư vô có thể men theo những sợi xích lôi quang để không lạc hướng. Cát Hồng dùng thiết kiếm tạo quầng sáng đi qua, còn Vương Lâm trực tiếp bước trên xích lôi, hấp thu lôi quang bằng thân thể và nguyên thần có lôi uy.","theLucLienQuan":[],"nguon":["@c0701"]},{"id":"hu-vo-trong-loi-tien-gioi","name":"Hư vô trong Lôi Tiên Giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Khu vực hư vô nơi nhóm Vương Lâm đi sâu bằng thiết kiếm và thân pháp. Lôi quang tại đây càng lúc càng dày đặc, đồng thời truyền tới chấn động bất thường từ phía trước.","detail":"Trong hư vô của Lôi Tiên Giới, Vương Lâm, Lý Nguyên và Cát Hồng phi hành gần hai tháng mà không gặp tu sĩ nào. Càng đi sâu, lôi quang càng nồng đậm, sợi xích lôi đình bắt đầu chấn động dữ dội và dẫn nhóm tới đám sương mù cấm chế chắn đường.","theLucLienQuan":[],"nguon":["@c0702"]},{"id":"dam-suong-mu-tien-khi-chan-duong","name":"Đám sương mù tiên khí chắn đường","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Vùng sương mù vô biên chắn toàn bộ đường đi trong Lôi Tiên Giới. Bên trong chứa cấm chế thiên cấp trung phẩm và là nơi lão già bí ẩn bước ra cuối chương.","detail":"Sau khi quyết định tiến về phía trước, Vương Lâm phát hiện một đám sương mù tiên khí khổng lồ chắn ngang toàn bộ đường đi. Lý Nguyên xác định đây là cấm chế, sau đó nhận ra nó thuộc thiên cấp trung phẩm và hình thành đại trận luyện hóa vạn vật; cuối chương, một lão già cầm sợi xích lôi quang bước ra từ chính vùng sương mù này.","theLucLienQuan":[],"nguon":["@c0702"]},{"id":"trung-tam-dai-luc-loi-tien-gioi","name":"Trung tâm đại lục","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Khu vực trung tâm của đại lục trong Lôi tiên giới, nơi Lý Nguyên dừng lại đối chiếu địa hình.","detail":"Sau một tháng phi hành, Lý Nguyên tới trung tâm đại lục để quan sát và so sánh với hình ảnh trong đầu. Từ đó hắn xác định cấm chế không ở tại đây mà nằm đại khái về phía đông.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"phia-dong-dai-luc-loi-tien-gioi","name":"Phía đông đại lục","cn":"","capDo":"khac","parentId":"dai-luc-manh-vo-trong-loi-tien-gioi","blurb":"Hướng Lý Nguyên xác định là nơi đại khái có cấm chế cần tìm trên đại lục Lôi tiên giới.","detail":"Sau khi rời trung tâm đại lục, Lý Nguyên dẫn Vương Lâm và Cát Hồng bay về phía đông. Hành trình này kéo dài ba tháng, vượt qua hư vô và một mảnh đại lục trước khi tới địa điểm cuối cùng.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"loi-quang-thien-lien-trong-hu-vo","name":"Lôi quang Thiên liên trong hư vô","cn":"","capDo":"khac","parentId":"hu-vo-trong-loi-tien-gioi","blurb":"Khu vực hư vô có Lôi quang Thiên liên mà ba người xuyên qua trên đường tới phía đông đại lục.","detail":"Trong hành trình ba tháng từ trung tâm đại lục tới nơi cấm chế, Vương Lâm, Lý Nguyên và Cát Hồng một lần nữa xâm nhập vùng Lôi quang Thiên liên trong hư vô rồi tiếp tục vượt qua một mảnh đại lục.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"ngon-nui-cao-vut-trong-may","name":"Ngọn núi cao vút trong mây","cn":"","capDo":"khac","parentId":"phia-dong-dai-luc-loi-tien-gioi","blurb":"Địa điểm Lý Nguyên nhìn thấy ở cuối hành trình và kích động xác nhận là nơi cần tìm.","detail":"Sau ba tháng phi hành về phía đông, Lý Nguyên nhìn chằm chằm ngọn núi cao vút trong mây và không giấu được kích động. Đây là điểm đến gắn với cấm chế mà hắn tìm kiếm trên đại lục trong Lôi tiên giới.","theLucLienQuan":[],"nguon":["@c0704"]},{"id":"ngon-nui-vo-danh-trong-loi-tien-gioi","name":"Ngọn núi vô danh trong Lôi tiên giới","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi cực cao trong Lôi tiên giới, sấm chớp bao quanh và cấm chế dày đặc. Lý Nguyên nói sâu trong núi có chủ nhân của hắn, đồng thời dùng nơi này để gây sức ép với Vương Lâm.","detail":"Ngọn núi mang dấu vết năm tháng, có nhiều cấm chế chưa bị bài trừ hoàn toàn dù Lôi tiên giới từng mở ra nhiều lần. Một con đường lên núi lộ ra nhờ các lớp cấm chế bị người đời trước phá dần; tại đây Lý Nguyên định giữ Vương Lâm lại, nhưng Vương Lâm dùng Tiên Vệ khôi lỗi mở dòng chảy thông ra ngoài.","theLucLienQuan":["Lôi tiên giới","Cát gia"],"nguon":["@c0705"]},{"id":"tien-phu-o-manh-dat-yeu-linh","name":"Tiên phủ ở mảnh đất Yêu Linh","cn":"","capDo":"khac","parentId":null,"blurb":"Tiên phủ tại mảnh đất Yêu Linh, nơi Vương Lâm từng lần đầu nhìn thấy dấu vết Mai hoa thuật còn sót lại. Ký ức này giúp hắn liên hệ cấm chế của Lý Nguyên với Mai hoa thuật.","detail":"Khi yêu cầu Mai hoa thuật từ Lý Nguyên, Vương Lâm nhớ lại mình từng thấy dấu vết còn sót của pháp môn này trong tiên phủ ở mảnh đất Yêu Linh. Đây là cơ sở quan trọng khiến hắn xem Mai hoa thuật là mục tiêu thật sự trong chuyến đi cùng Lý Nguyên.","theLucLienQuan":[],"nguon":["@c0705"]},{"id":"ngon-nui-do-tu-dai-cam-thuat-tan-vo-tao-thanh","name":"Ngọn núi do tứ đại cấm thuật tan vỡ tạo thành","cn":"","capDo":"khac","parentId":"loi-tien-gioi","blurb":"Ngọn núi đặc biệt trong Lôi Tiên Giới được Lý Nguyên nói là do tứ đại cấm thuật tan vỡ tạo thành. Nếu không biết cách hóa giải, người vào núi sẽ không thấy điểm cuối.","detail":"Lý Nguyên đưa Vương Lâm tới ngọn núi này để tìm đến nơi cất giấu bí mật liên quan chủ nhân hắn. Hắn dùng cấm chế và phương pháp hóa giải khiến ngọn núi nhiều lần chấn động, thu nhỏ dần, cuối cùng để lộ đỉnh núi.","theLucLienQuan":["Cát gia"],"nguon":["@c0706"]},{"id":"dinh-nui-cam-thuat","name":"Đỉnh núi","cn":"","capDo":"khac","parentId":"ngon-nui-do-tu-dai-cam-thuat-tan-vo-tao-thanh","blurb":"Đỉnh núi là nơi hiện ra tượng đá trung niên nam tử, thanh phi kiếm và người đứng trên mũi kiếm. Đây là điểm Lý Nguyên hướng tới và nơi Vương Lâm bị kéo vào huyễn cảnh.","detail":"Sau khi Lý Nguyên nhiều lần phá cấm và thu nhỏ ngọn núi, đỉnh núi xuất hiện trong tầm mắt. Tại đây có tượng đá cao lớn cùng thanh phi kiếm, trên mũi kiếm có một người, và ấn quyết trên tượng đá dẫn Vương Lâm vào cảnh tượng Tiên giới xa xưa.","theLucLienQuan":[],"nguon":["@c0706"]},{"id":"chien-truong-tien-gioi-trong-huyen-canh","name":"Chiến trường Tiên giới trong huyễn cảnh","cn":"","capDo":"khac","parentId":"dinh-nui-cam-thuat","blurb":"Chiến trường Tiên giới trong huyễn cảnh là không gian Vương Lâm nhìn thấy khi bị ấn quyết trên tượng đá hút tâm thần. Nơi đó có tiên nhân lôi điện giao chiến, bảo kiếm tím và cảnh chủ nhân trên chuôi kiếm tan rã.","detail":"Trong huyễn cảnh, Vương Lâm thấy nhiều tiên nhân lượn lờ, quanh người có lôi điện, thỉnh thoảng có người nổ tung mà chết dù không thấy địch nhân. Sau đó thanh bảo kiếm tím xuất hiện, chở nam tử trên chuôi kiếm và người hầu trên mũi kiếm, tái hiện cảnh chủ chết, đầy tớ đi theo.","theLucLienQuan":["Tiên giới"],"nguon":["@c0706"]}]};
